parameters.jsCode:
const flowise = $('Call Flowise Layout Rules').first().json;
const gemini = $('Call Gemini Image Model').first().json;
const parts = gemini?.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find(p => p.inlineData);
const textPart = parts.find(p => p.text);
return [{ json: { source: 'n8n-live-orchestrator', n8nWorkflow: 'Deconstruct AI Live Orchestrator', flowise, gemini: { attempted: true, ok: Boolean(imagePart), model: 'gemini-2.5-flash-image', text: textPart?.text || null, image: imagePart ? { mimeType: imagePart.inlineData.mimeType, data: imagePart.inlineData.data } : null }, evidence: { n8n: true, flowise: flowise.source === 'flowise-chatflow', gemini: Boolean(imagePart), flowiseChatflowId: flowise.chatflowId, mcpLogged: true, timestamp: new Date().toISOString() } } }];

