={{ (() => {
      const body = $('Design Request Webhook').first().json.body || {};
      const flowise = $('Call Flowise Layout Rules').first().json || {};
      const text = body.caption || (body.userCopyTexts || [''])[0] || '';
      const designType = body.designType || 'design';
      return {
        contents: [{
          parts: [{
            text: 'Create a polished, production-quality ' + designType + ' with exact visible text: "' + text + '". Use these layout rules from Flowise: ' + JSON.stringify(flowise.layoutRules || {}) + '. Output a real AI-generated marketing graphic, not a schema, mockup, wireframe, placeholder, or flat canvas render.'
          }]
        }],
        generationConfig: { responseModalities: ['TEXT','IMAGE'] }
      };
    })() }}
